### Option 2: Render in Your Browser (HTML/JS)
If you want to see the model immediately without installing anything, copy the code below into a text file, save it as `house.html`, and open it in Chrome, Firefox, or Edge.

This uses **Three.js** to render a 3D house with lighting and rotation.

```html
<!DOCTYPE html>
<html>
<head>
    <title>3D House Model</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            font-family: Arial, sans-serif;
            color: white;
            font-weight: bold;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">Click & Drag to Rotate | Scroll to Zoom</div>

    <!-- Load Three.js from CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        const camera = new THREE.PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 10, 15);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        document.body.appendChild(renderer.domElement);

        // 2. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        scene.add(dirLight);

        // 3. Create the House
        const houseGroup = new THREE.Group();

        // Materials
        const wallMaterial = new THREE.MeshStandardMaterial({ color: 0xffffff }); // White walls
        const roofMaterial = new THREE.MeshStandardMaterial({ color: 0x8B4513 }); // Brown roof
        const floorMaterial = new THREE.MeshStandardMaterial({ color: 0x228B22 }); // Green grass

        // Floor
        const floorGeo = new THREE.PlaneGeometry(50, 50);
        const floor = new THREE.Mesh(floorGeo, floorMaterial);
        floor.rotation.x = -Math.PI / 2;
        floor.receiveShadow = true;
        scene.add(floor);

        // Walls (Box)
        const wallGeo = new THREE.BoxGeometry(8, 6, 8);
        const walls = new THREE.Mesh(wallGeo, wallMaterial);
        walls.position.y = 3;
        walls.castShadow = true;
        walls.receiveShadow = true;
        houseGroup.add(walls);

        // Roof (Pyramid)
        const roofGeo = new THREE.ConeGeometry(7, 4, 4);
        const roof = new THREE.Mesh(roofGeo, roofMaterial);
        roof.position.y = 8; // Sit on top of walls
        roof.rotation.y = Math.PI / 4; // Rotate to align with square base
        roof.castShadow = true;
        houseGroup.add(roof);

        // Door
        const doorGeo = new THREE.BoxGeometry(2, 4, 0.2);
        const doorMat = new THREE.MeshStandardMaterial({ color: 0x8B0000 });
        const door = new THREE.Mesh(doorGeo, doorMat);
        door.position.set(0, 2, 4.1); // Front center
        houseGroup.add(door);

        // Windows
        const winGeo = new THREE.BoxGeometry(2, 2, 0.1);
        const winMat = new THREE.MeshStandardMaterial({ color: 0xADD8E6 });

        const win1 = new THREE.Mesh(winGeo, winMat);
        win1.position.set(-2.5, 4, 4.1);
        houseGroup.add(win1);

        const win2 = new THREE.Mesh(winGeo, winMat);
        win2.position.set(2.5, 4, 4.1);
        houseGroup.add(win2);

        scene.add(houseGroup);

        // 4. Controls
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;

        // 5. Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle window resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
```

### Which should you use?
*   **Use Option 1 (Python)** if you need a file to import into professional 3D software (Blender, Maya, Unity, Unreal Engine).
*   **Use Option 2 (HTML)** if you want to visualize the model instantly in a web browser or embed it on a website.
